What does this program print?

```cpp
#include <iostream>

void printA() {
    using std::cout;
    cout << "A\n";
}

int main() {
    printA();
    std::cout << "B\n";
    return 0;
}
```

What does this program print?

```cpp
#include <iostream>

int main() {
    {
        using namespace std;
        cout << "inner\n";
    }
    std::cout << "outer\n";
    return 0;
}
```

